const runId = `run_${Date.now()}`;
const runAt = new Date().toISOString();
console.log(`[Pipeline] Starting run: ${runId}`);
return [{ json: { runId, runAt } }];

const err = $input.item.json.error || 'Unknown error';
console.error(`[Pipeline] Earnings feed failed: ${err}`);
return [];

const err = $input.item.json.error || 'Unknown error';
console.error(`[Pipeline] Regulatory feed failed: ${err}`);
return [];

// Parse RSS XML and extract article metadata
const body = $input.item.json.data || '';
const MAX = 1;

const blocks = (body.match(/<item>(.*?)<\/item>/gs) || []).slice(0, MAX);
const items = [];

for (const block of blocks) {
  const title   = (block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
  const url     = (block.match(/<link>(.*?)<\/link>/) || [])[1] || '';
  const desc    = (block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/) || [])[1] || '';
  const pubDate = (block.match(/<pubDate>(.*?)<\/pubDate>/) || [])[1] || '';

  if (title && url) {
    items.push({ json: {
      title: title.trim(),
      url: url.trim(),
      description: desc.replace(/<[^>]+>/g, '').trim().slice(0, 600),
      pubDate,
      sourceType: 'earnings',
      sourceName: 'CNBC Earnings'
    }});
  }
}

console.log(`[Pipeline] Parsed ${items.length} earnings items`);
return items;

// Parse RSS and keyword-filter for AI relevance
const body = $input.item.json.data || '';
const MAX = 1;

const KEYWORDS = [
  'artificial intelligence', 'AI', 'machine learning',
  'automation', 'LLM', 'AI governance', 'AI compliance',
  'AI regulation', 'AI Act', 'cybersecurity'
];

const blocks = body.match(/<item>(.*?)<\/item>/gs) || [];
const items = [];

for (const block of blocks) {
  if (items.length >= MAX) break;

  const title   = (block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
  const url     = (block.match(/<link>(.*?)<\/link>/) || [])[1] || '';
  const desc    = (block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/) || [])[1] || '';
  const pubDate = (block.match(/<pubDate>(.*?)<\/pubDate>/) || [])[1] || '';

  const combined = (title + ' ' + desc).toLowerCase();
  const isRelevant = KEYWORDS.some(kw => combined.includes(kw.toLowerCase()));

  if (isRelevant && title && url) {
    items.push({ json: {
      title: title.trim(),
      url: url.trim(),
      description: desc.replace(/<[^>]+>/g, '').trim().slice(0, 600),
      pubDate,
      sourceType: 'regulatory',
      sourceName: 'NIST'
    }});
  }
}

console.log(`[Pipeline] Parsed ${items.length} regulatory items`);
return items;

// Merge streams + generate hash
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}

const items = $input.all();
const result = [];

for (const item of items) {
  const { title, url } = item.json;
  if (!title || !url) continue;
  const hash = simpleHash(title + url);
  result.push({ json: { ...item.json, hash } });
}

console.log(`[Pipeline] ${result.length} items ready for memory check`);
return result;

// Check duplicate count and pass through original data
const item = $input.item.json;
const count = parseInt(item.duplicate_count || '0');

if (count > 0) {
  console.log('[Pipeline] Duplicate, skipping: ' + item.title);
  return [];
}

console.log('[Pipeline] New item: ' + item.title);
return [{ json: {
  hash: item.hash,
  title: item.title,
  url: item.url,
  sourceType: item.source_type,
  sourceName: item.source_name,
  description: item.description
} }];

// Build Brand DNA config and inject into AI prompt
const brandDNA = {
  voice: 'Direct, sharp, slightly contrarian. Practitioner who has seen things fail.',
  hook: 'Open with a surprising stat or uncomfortable truth. Never start with I or In todays.',
  structure: 'Short punchy paragraphs. Max 2 sentences each.',
  cta: 'End with a quiet open question — not a hard sell.',
  length: '150-220 words',
  emoji: 'Maximum 1, only for directional emphasis like arrow down',
  hashtags: 'Exactly 3, always on the very last line',
  forbidden: 'leverage, synergy, ecosystem, game-changer, delve, robust, seamless, cutting-edge',
  rules: [
    'Always anchor to real data or a named source',
    'Never make predictions — focus on what the data shows now',
    'Every paragraph should feel like it is about the reader, not the writer',
    'If it sounds like a vendor pitch, rewrite it'
  ]
};

const item = $input.item.json;

const prompt = `You are a ghostwriter for a senior enterprise AI practitioner publishing on LinkedIn.

BRAND DNA — NON-NEGOTIABLE RULES:
Voice: ${brandDNA.voice}
Hook style: ${brandDNA.hook}
Structure: ${brandDNA.structure}
Closing: ${brandDNA.cta}
Length: ${brandDNA.length}
Emoji: ${brandDNA.emoji}
Hashtags: ${brandDNA.hashtags}
Forbidden words: ${brandDNA.forbidden}
Rules:
${brandDNA.rules.map(r => '- ' + r).join('\n')}

Write a LinkedIn post based on this ${item.sourceType} update:
Title: ${item.title}
Source: ${item.sourceName}
Summary: ${item.description}

Find the ONE most surprising or counterintuitive truth in this source and build the post around it.
Return ONLY the post text. No preamble. No quotation marks. No markdown.`;

return [{ json: { ...item, prompt } }];

// Extract post text from Gemini and carry forward all item data
const output = $input.item.json.output || $input.item.json.text || '';

if (!output.trim()) {
  console.log('[Pipeline] Gemini returned empty output');
  return [];
}

// Get original item data from Inject Brand DNA node
const original = $('Inject Brand DNA1').first().json;

console.log('[Pipeline] Post drafted — ' + output.trim().split(' ').length + ' words');

return [{ json: {
  hash: original.hash,
  title: original.title,
  url: original.url,
  sourceType: original.sourceType,
  sourceName: original.sourceName,
  description: original.description,
  postText: output.trim()
} }];

