// Validate HMAC token
const { hash, token, action } = $input.item.json.query || {};

if (!hash || !token || !['approve','reject'].includes(action)) {
  return [{ json: { valid: false, reason: 'Bad parameters' } }];
}

function simpleHash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    h = ((h << 5) - h) + char;
    h = h & h;
  }
  return Math.abs(h).toString(16).padStart(8, '0');
}

const expected = simpleHash(hash + 'dev-secret');

if (token !== expected) {
  return [{ json: { valid: false, reason: 'Invalid token' } }];
}

return [{ json: { valid: true, hash, action } }];

